    17→/* ---------- Inline Add Source Form ---------- */
    18→
    19→function InlineSourceForm({
    20→  projectId,
    21→  onDone,
    22→}: {
    23→  projectId: string;
    24→  onDone: () => void;
    25→}) {
    26→  const [provider, setProvider] = useState("github");
    27→  const [repository, setRepository] = useState("");
    28→  const [pollInterval, setPollInterval] = useState("300");
    29→  const [saving, setSaving] = useState(false);
    30→  const [error, setError] = useState("");
    31→
    32→  const handleAdd = async (e: React.FormEvent) => {
    33→    e.preventDefault();
    34→    if (!repository.trim()) return;
    35→    setSaving(true);
    36→    setError("");
    37→    try {
    38→      await sourcesApi.create(projectId, {
    39→        provider,
    40→        repository: repository.trim(),
    41→        poll_interval_seconds: Number(pollInterval) || 300,
    42→        enabled: true,
    43→      });
    44→      mutate(`project-${projectId}-card-sources`);
    45→      onDone();
    46→    } catch (err: unknown) {
    47→      setError(err instanceof Error ? err.message : "Failed to add source");
    48→    } finally {
    49→      setSaving(false);
    50→    }
    51→  };
    52→
    53→  return (
    54→    <form onSubmit={handleAdd} className="mt-2 rounded-md border p-3 space-y-2" style={{ borderColor: "#e8e8e5", backgroundColor: "#fafaf9" }}>
    55→      {error && <div className="text-[12px] text-red-600">{error}</div>}
    56→      <div className="flex items-center gap-2">
    57→        <select
    58→          value={provider}
    59→          onChange={(e) => setProvider(e.target.value)}
    60→          className="rounded-md border px-2 py-1 text-[12px]"
    61→          style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)" }}
    62→        >
    63→          <option value="github">GitHub</option>
    64→          <option value="dockerhub">Docker Hub</option>
    65→        </select>
    66→        <input
    67→          type="text"
    68→          value={repository}
    69→          onChange={(e) => setRepository(e.target.value)}
    70→          placeholder="e.g. ethereum/go-ethereum"
    71→          className="flex-1 rounded-md border px-2 py-1 text-[12px]"
    72→          style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
    73→        />
    74→        <input
    75→          type="number"
    76→          min={60}
    77→          value={pollInterval}
    78→          onChange={(e) => setPollInterval(e.target.value)}
    79→          className="w-20 rounded-md border px-2 py-1 text-[12px]"
    80→          style={{ borderColor: "#e8e8e5" }}
    81→          title="Poll interval (seconds)"
    82→        />
    83→      </div>
    84→      <div className="flex items-center justify-end gap-2">
    85→        <button
    86→          type="button"
    87→          onClick={onDone}
    88→          className="text-[12px] text-[#9ca3af] hover:text-[#6b7280]"
    89→        >
    90→          Cancel
    91→        </button>
    92→        <button
    93→          type="submit"
    94→          disabled={saving || !repository.trim()}
    95→          className="rounded-md px-3 py-1 text-[12px] font-medium text-white disabled:opacity-40"
    96→          style={{ backgroundColor: "#e8601a" }}
    97→        >
    98→          {saving ? "Adding..." : "Add"}
    99→        </button>
   100→      </div>
   101→    </form>
   102→  );
   103→}
   104→
   105→/* ---------- Sources Section ---------- */
   106→
   107→function SourcesSection({ projectId }: { projectId: string }) {
   108→  const [adding, setAdding] = useState(false);
   109→  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
   110→    sourcesApi.listByProject(projectId)
   111→  );
   112→  const sources = data?.data ?? [];
   113→
   114→  return (
   115→    <div className="px-4 py-3 md:border-r" style={{ borderColor: "#e8e8e5" }}>
   116→      <div className="flex items-center justify-between mb-1">
   117→        <span
   118→          className="text-[11px] font-medium uppercase tracking-[0.08em]"
   119→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   120→        >
   121→          Sources
   122→        </span>
   123→        {!adding && (
   124→          <button
   125→            onClick={() => setAdding(true)}
   126→            className="inline-flex items-center gap-1 text-[11px] font-medium transition-colors hover:opacity-80"
   127→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   128→          >
   129→            <Plus className="h-3 w-3" />
   130→            Add Source
   131→          </button>
   132→        )}
   133→        {adding && (
   134→          <button
   135→            onClick={() => setAdding(false)}
   136→            className="text-[#9ca3af] hover:text-[#6b7280]"
   137→          >
   138→            <X className="h-3.5 w-3.5" />
   139→          </button>
   140→        )}
   141→      </div>
   142→
   143→      {sources.length > 0 ? (
   144→        <div className="space-y-1">
   145→          {sources.map((source) => {
   146→            const Icon = getProviderIcon(source.provider);
   147→            return (
   148→              <div
   149→                key={source.id}
   150→                className="flex items-center gap-2 text-[12px]"
   151→                style={{ fontFamily: "var(--font-dm-sans)" }}
   152→              >
   153→                {Icon && <Icon size={13} className="shrink-0" style={{ color: "#6b7280" }} />}
   154→                <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
   155→                  {source.repository}
   156→                </span>
   157→                <span
   158→                  className="ml-auto flex items-center gap-1.5 text-[11px]"
   159→                  style={{ color: "#9ca3af" }}
   160→                >
   161→                  <span
   162→                    className="inline-block h-1.5 w-1.5 rounded-full"
   163→                    style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
   164→                  />
   165→                  {source.enabled ? "Active" : "Disabled"}
   166→                  <span className="ml-1" style={{ color: "#c4c4c0" }}>
   167→                    {source.poll_interval_seconds < 60
   168→                      ? `${source.poll_interval_seconds}s`
   169→                      : source.poll_interval_seconds < 3600
   170→                        ? `${Math.round(source.poll_interval_seconds / 60)}m`
   171→                        : `${(source.poll_interval_seconds / 3600).toFixed(1)}h`}
   172→                  </span>
   173→                </span>
   174→              </div>
   175→            );
   176→          })}
   177→        </div>
   178→      ) : (
   179→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   180→          No sources configured
   181→        </p>
   182→      )}
   183→
   184→      {adding && (
   185→        <InlineSourceForm projectId={projectId} onDone={() => setAdding(false)} />
   186→      )}
   187→    </div>
   188→  );
   189→}
   190→
   191→/* ---------- Recent Releases Section ---------- */
   192→
   193→function RecentReleasesSection({ projectId }: { projectId: string }) {
   194→  const { data: relData } = useSWR(`project-${projectId}-card-releases`, () =>
   195→    releasesApi.listByProject(projectId, 1, 5)
   196→  );
   197→  const { data: srcData } = useSWR(`project-${projectId}-card-sources`, () =>
   198→    sourcesApi.listByProject(projectId)
   199→  );
   200→  const releases = relData?.data ?? [];
   201→  const sources = srcData?.data ?? [];
   202→
   203→  const sourceMap = new Map<string, Source>();
   204→  for (const s of sources) sourceMap.set(s.id, s);
   205→
   206→  return (
   207→    <div className="border-t md:border-t-0 md:border-r px-4 py-3" style={{ borderColor: "#e8e8e5" }}>
   208→      <span
   209→        className="text-[11px] font-medium uppercase tracking-[0.08em] mb-1 block"
   210→        style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   211→      >
   212→        Recent Releases
   213→      </span>
   214→
   215→      {releases.length > 0 ? (
   216→        <div className="space-y-1">
   217→          {releases.map((r) => {
   218→            const src = sourceMap.get(r.source_id);
   219→            const Icon = src ? getProviderIcon(src.provider) : undefined;
   220→            return (
   221→              <Link
   222→                key={r.id}
   223→                href={`/releases/${r.id}`}
   224→                className="flex items-center gap-2 text-[12px] transition-colors hover:bg-[#fafaf9] rounded px-1 -mx-1 py-0.5"
   225→              >
   226→                <span
   227→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none"
   228→                  style={{
   229→                    backgroundColor: "#f3f3f1",
   230→                    fontFamily: "'JetBrains Mono', monospace",
   231→                    color: "#374151",
   232→                  }}
   233→                >
   234→                  {r.version}
   235→                </span>
   236→                {Icon && <Icon size={11} className="shrink-0" style={{ color: "#9ca3af" }} />}
   237→                {src && (
   238→                  <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   239→                    {src.repository}
   240→                  </span>
   241→                )}
   242→                <span className="ml-auto text-[11px] shrink-0" style={{ color: "#c4c4c0" }}>
   243→                  {timeAgo(r.released_at || r.created_at)}
   244→                </span>
   245→              </Link>
   246→            );
   247→          })}
   248→          <Link
   249→            href={`/releases?project=${projectId}`}
   250→            className="block text-[11px] mt-1 hover:underline"
   251→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   252→          >
   253→            View all &rarr;
   254→          </Link>
   255→        </div>
   256→      ) : (
   257→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   258→          No releases yet
   259→        </p>
   260→      )}
   261→    </div>
   262→  );
   263→}
   264→
   265→/* ---------- Semantic Releases Section ---------- */
   266→
   267→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
   268→  critical: { bg: "#dc2626", text: "#ffffff" },
   269→  high: { bg: "#f97316", text: "#ffffff" },
   270→};
   271→
   272→function SemanticReleasesSection({ projectId }: { projectId: string }) {
   273→  const { data } = useSWR(`project-${projectId}-card-sr`, () =>
   274→    srApi.list(projectId, 1, 3)
   275→  );
   276→  const items = data?.data ?? [];
   277→
   278→  return (
   279→    <div className="border-t md:border-t-0 px-4 py-3" style={{ borderColor: "#e8e8e5" }}>
   280→      <span
   281→        className="text-[11px] font-medium uppercase tracking-[0.08em] mb-1 block"
   282→        style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   283→      >
   284→        Semantic Releases
   285→      </span>
   286→
   287→      {items.length > 0 ? (
   288→        <div className="space-y-1">
   289→          {items.map((sr) => {
   290→            const urgencyStyle = sr.report?.urgency
   291→              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
   292→              : undefined;
   293→            return (
   294→              <Link
   295→                key={sr.id}
   296→                href={`/projects/${projectId}/semantic-releases/${sr.id}`}
   297→                className="flex items-center gap-2 text-[12px] transition-colors hover:bg-[#fafaf9] rounded px-1 -mx-1 py-0.5"
   298→              >
   299→                <span
   300→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none"
   301→                  style={{
   302→                    backgroundColor: "#eff6ff",
   303→                    fontFamily: "'JetBrains Mono', monospace",
   304→                    color: "#1d4ed8",
   305→                  }}
   306→                >
   307→                  {sr.version}
   308→                </span>
   309→                <span
   310→                  className="text-[11px]"
   311→                  style={{ color: "#9ca3af" }}
   312→                >
   313→                  {sr.status}
   314→                </span>
   315→                {urgencyStyle && (
   316→                  <span
   317→                    className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none"
   318→                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   319→                  >
   320→                    {sr.report!.urgency}
   321→                  </span>
   322→                )}
   323→                {sr.report?.summary && (
   324→                  <span
   325→                    className="text-[11px] truncate flex-1"
   326→                    style={{ color: "#c4c4c0" }}
