   332→                )}
   333→                <span className="ml-auto text-[11px] shrink-0" style={{ color: "#c4c4c0" }}>
   334→                  {timeAgo(sr.completed_at || sr.created_at)}
   335→                </span>
   336→              </Link>
   337→            );
   338→          })}
   339→          <Link
   340→            href={`/projects/${projectId}`}
   341→            className="block text-[11px] mt-1 hover:underline"
   342→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   343→          >
   344→            View all &rarr;
   345→          </Link>
   346→        </div>
   347→      ) : (
   348→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   349→          No semantic releases yet
   350→        </p>
   351→      )}
   352→    </div>
   353→  );
   354→}
