   356→/* ---------- Project Card ---------- */
   357→
   358→function ProjectCard({ project }: { project: Project }) {
   359→  return (
   360→    <div
   361→      className="overflow-hidden rounded-md"
   362→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   363→    >
   364→      {/* Header */}
   365→      <div className="px-4 py-3">
   366→        <div className="min-w-0">
   367→          <Link
   368→            href={`/projects/${project.id}`}
   369→            className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors"
   370→            style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a" }}
