     9→import type { IconType } from "react-icons";
    10→
    11→const TYPE_STYLES: Record<string, { bg: string; text: string; icon: IconType }> = {
    12→  slack: { bg: "#4A154B", text: "#ffffff", icon: FaSlack },
    13→  discord: { bg: "#5865F2", text: "#ffffff", icon: FaDiscord },
    14→  webhook: { bg: "#1a1a1a", text: "#ffffff", icon: TbWebhook },
    15→};
    16→
    17→function TypeBadge({ type }: { type: string }) {
    18→  const style = TYPE_STYLES[type.toLowerCase()];
    19→  const colors = style ?? { bg: "#6b7280", text: "#ffffff" };
    20→  const Icon = style?.icon;
    21→  return (
    22→    <span
    23→      className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5"
    24→      style={{
